    const pageInfo = await graphApi(`${pageId}?fields=followers_count`, token, 'GET');

    // 2. Get Insights (Reach, Engagement)
    // Using widely supported metrics.
    // page_impressions_unique: Total Reach (Daily, Days_28)
    // page_engaged_users: People who engaged with page (Daily, Days_28)
    const insights = await graphApi(
        `${pageId}/insights?metric=page_impressions_unique,page_engaged_users&period=days_28`, 
        token, 
        'GET'
    );

    const followers = pageInfo.followers_count || 0;

    // Safely extract values
    const getMetricValue = (name: string) => {
        const metric = insights.data?.find((d: any) => d.name === name);
        // values is usually an array of objects { value: number, end_time: string }
        // We take the most recent complete period (index 0 or 1 depending on API response order, typically 0 for single period request)
        return metric?.values?.[0]?.value || 0;
    };

    const reach = getMetricValue('page_impressions_unique');
    const engagedUsers = getMetricValue('page_engaged_users');

